  6: "6 месяцев",
  12: "12 месяцев",
};

const pricingData = {
  mass: {
    1: { monthly: 2900, total: 2900 },
    3: { monthly: 2633, total: 7900 },
    6: { monthly: 2483, total: 14900 },
    12: { monthly: 1992, total: 23900 },
  },
