    3: { monthly: 2000, savings: 600 },
    6: { monthly: 1900, savings: 1800 },
    12: { monthly: 1800, savings: 4800 },
  },
  // Тариф VK (Скриншот 3)
  vk: {
    1: { monthly: 990, total: 990 },
    3: { monthly: 990, total: 2970 },
    6: { monthly: 990, total: 5940 },
    12: { monthly: 990, total: 11880 },
  },
};

const currentPrices = computed(() => {
  const p = currentPeriod.value;
  const channelBase = pricingData.channels[p].monthly;

  return {
    mass: pricingData.mass[p],
    oneChannel: pricingData.channels[p],

    twoChannels: {
      perChannel: Math.round(channelBase * 0.85),
      total: Math.round(channelBase * 0.85 * 2),
    },
    vk: pricingData.vk[p],
  };
});
</script>

